mapper.select:
SELECT ch.* from wc_checkout ch left join
uc_customer cu on ch.customerId = cu.id WHERE 1 = 1


    AND (
    ch.`code` LIKE concat('%', #{query.name}, '%') OR
    cu.`code` LIKE concat('%', #{query.name}, '%') OR
    cu.`name` LIKE concat('%', #{query.name}, '%')
    )



    AND ch.`issueDate`  >=  #{query.startDate}


    AND ch.`issueDate`  <=  #{query.endDate}


ORDER BY ch.createdTime DESC
